#include <bits/stdc++.h> 
using namespace std;
int n,a[3005],dp[3005][3005];
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int len=2;len<=n;len++)
	{
		for(int l=1,r=len;r<=n;l++,r++)
		{
			dp[l][r]=dp[l+1][r-1];
			if(a[l]!=a[r]) dp[l][r]++;
			dp[l][r]=min(dp[l][r],min(dp[l+1][r],dp[l][r-1])+1);
		}
	}
	cout<<dp[1][n];
	return 0;
}
